import{_ as e,c as o,o as t,a4 as i}from"./chunks/framework.DB6FXu2X.js";const f=JSON.parse('{"title":"About PR (Pull Request)","description":"","frontmatter":{"title":"About PR (Pull Request)","prev":{"text":"About the structure of json file","link":"../completion/index.md"}},"headers":[],"relativePath":"en-US/contribute/index.md","filePath":"en-US/contribute/index.md"}'),l={name:"en-US/contribute/index.md"},n=i('<h1 id="about-pr-pull-request" tabindex="-1">About PR (Pull Request) <a class="header-anchor" href="#about-pr-pull-request" aria-label="Permalink to &quot;About PR (Pull Request)&quot;">​</a></h1><ol><li>Prerequisite: You should read <a href="./../completion/">About the structure of completion json file</a> first.</li><li>You should fork <a href="https://github.com/abgox/PSCompletions" target="_blank" rel="noreferrer">PSCompletions</a>, and clone to your machine.</li><li>After Changing, you should commit and create the <code>PR</code>.</li></ol><h2 id="_1-update-the-content-of-completion-json-file" tabindex="-1">1. Update the content of completion json file <a class="header-anchor" href="#_1-update-the-content-of-completion-json-file" aria-label="Permalink to &quot;1. Update the content of completion json file&quot;">​</a></h2><ul><li>Patch some tips of the completion.(<code>tip</code> attributes)</li><li>Add some missing parts for the completion. <ul><li>The missing parts can be viewed by using the <code>compareJson.ps1</code> script. <ul><li>Take <code>git</code> for example.</li><li>You can view the missing parts of the <code>zh-CN.json</code> file (Compared to the <code>en-US.json</code> file) by using the following command. <ul><li><code>.\\script\\compareJson.ps1 .\\completions\\git\\language\\zh-CN.json .\\completions\\git\\language\\en-US.json</code></li></ul></li><li>If it&#39;s compared to the first language configured in <code>config.json</code>, the second parameter can also be omitted. <ul><li>It&#39;s usually compared to the first language, so the following commands are the most common usage.</li><li><code>.\\script\\compareJson.ps1 .\\completions\\git\\language\\zh-CN.json</code></li></ul></li></ul></li></ul></li></ul><h2 id="_2-add-language" tabindex="-1">2. Add language <a class="header-anchor" href="#_2-add-language" aria-label="Permalink to &quot;2. Add language&quot;">​</a></h2><ol><li>In the <code>completions</code> directory, select the language you want to add.</li><li>Add the language identifier to the language in the <code>config.json</code> file.</li><li>Add a json file with the same name as the language identifier in the <code>language</code> directory. <ul><li>You can copy the original json file and rename it.</li></ul></li><li>Translate the contents of the <code>tip</code> attribute.</li></ol><h2 id="_3-add-a-new-completion" tabindex="-1">3. Add a new completion <a class="header-anchor" href="#_3-add-a-new-completion" aria-label="Permalink to &quot;3. Add a new completion&quot;">​</a></h2><ol><li>Run it in the project root directory. <code>.\\script\\create.ps1</code><ul><li>For the convenience of debugging, <code>create.ps1</code> will link the created completion directory to the <code>completions</code> directory of the <code>PSCompletions</code> module. <ul><li>So <code>PSCompletions</code> module must be installed and imported before running <code>create.ps1</code>. <ul><li><code>Install-Module PSCompletions -Scope CurrentUser</code></li><li><code>Import-Module PSCompletions</code></li></ul></li></ul></li><li>After the <code>PR</code> is committed and merged, you should use <code>psc rm</code> to remove this completion and <code>psc add</code> to re-add it.</li></ul></li><li>Follow the prompts.</li><li>Modify the new completion.</li><li>Modify <code>config.json</code> as required.</li></ol>',8),a=[n];function c(d,r,s,u,h,p){return t(),o("div",null,a)}const g=e(l,[["render",c]]);export{f as __pageData,g as default};
